body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background-color: #f0f2f5; padding: 20px; color: #333; margin: 0; }
.container { max-width: 1100px; margin: 10px auto; background: white; padding: 10px; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.08); box-sizing: border-box; }
.center-text { text-align: center; }

/* Login Box */
#login-box { max-width: 400px; margin: 0 auto; padding: 20px; }
input { width: 100%; padding: 12px; margin: 15px 0; border: 1px solid #ccc; border-radius: 6px; box-sizing: border-box; font-size: 16px; }
button { background: #007bff; color: white; padding: 12px 24px; border: none; border-radius: 6px; cursor: pointer; font-size: 16px; width: 100%; font-weight: bold; }
button:hover { background: #0056b3; }
.error { color: #dc3545; font-weight: bold; margin-top: 15px; }
.hidden { display: none; }

/* Dashboard & Layout */
.welcome-header { border-bottom: 2px solid #007bff; padding-bottom: 10px; margin-bottom: 25px; display: flex; justify-content: space-between; align-items: center; }
.section-title { background: #007bff; color: white; padding: 8px 15px; font-size: 16px; font-weight: bold; border-radius: 4px; margin-top: 25px; margin-bottom: 10px; text-transform: uppercase; }

/* Horizontal Table Styling */
.table-responsive { width: 100%; overflow-x: auto; margin-bottom: 20px; }
table { width: 100%; border-collapse: collapse; min-width: 800px; }
th, td { padding: 10px 12px; border: 1px solid #dee2e6; text-align: center; font-size: 13px; }
th { background-color: #f8f9fa; color: #495057; font-weight: 600; }

.logout-btn { background: #6c757d; width: auto; padding: 10px 20px; }
.logout-btn:hover { background: #5a6268; }

    async function loginUser() {
        const inputCode = document.getElementById('membercode-input').value.trim();

        if (!inputCode) {
            showError("Kripya Member Code enter karein!");
            return;
        }

        try {
            const response = await fetch('data.json');
            if (!response.ok) throw new Error("data.json file nahi mili.");

            const employees = await response.json();

            // Member Code case-insensitive check
            const emp = employees.find(e => e["Member Code"] && e["Member Code"].toString().toLowerCase() === inputCode.toLowerCase());

            if (emp) {
                showDashboard(emp);
            } else {
                showError("Galat Member Code! Kripya sahi code dalein.");
            }
        } catch (error) {
            showError("Error: " + error.message);
        }
    }

