async function saveEmailToSheet() {
    const email = document.getElementById('userEmail').value.trim();
    const statusText = document.getElementById('email-status');
    // Login box se member code uthana
    const memberCode = document.getElementById('membercode-input').value.trim(); 

    if (!email) {
        statusText.style.color = "#dc3545";
        statusText.innerText = "Kripya ek valid email enter karein!";
        return;
    }

    statusText.style.color = "#007bff";
    statusText.innerText = "Email save ho raha hai...";

    // Apne Google Apps Script Web App ka URL yahan dalein
    const webAppUrl = "https://script.google.com/macros/s/AKfycbxupnUXo62b_vCIR4nQ_Zhpd2o3mV1L4qcCfAsjV8C_kznniYnj9CAmRM90HlIsPmoVDg/exec"; 

    const data = {
        action: "saveEmail",
        userId: memberCode,
        email: email
    };

    try {
        await fetch(webAppUrl, {
            method: 'POST',
            mode: 'no-cors',
            cache: 'no-cache',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });

        statusText.style.color = "#28a745";
        statusText.innerText = "✔ Email safaltapoorvak save ho gaya hai!";
        document.getElementById('userEmail').value = ""; // Input clear karne ke liye
    } catch (error) {
        statusText.style.color = "#dc3545";
        statusText.innerText = "Error: Email save nahi ho paya.";
        console.error(error);
    }
}
